<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>VanillaJS Kanban Board</title>
    <link href="https://cdn.jsdelivr.net/tailwind/latest/tailwind.css" rel="stylesheet">
    <style>
        /* Add some subtle transitions */
        .card {
            transition: transform 0.2s ease-in-out;
        }

        .card.dragging {
            opacity: 0.7;
            transform: translate(-10px, -10px); /* Adjust as needed */
        }

        .card.drop-target {
            border: 2px dashed #3490f6; /* Indicate drop target */
        }

        /* Confetti animation styles (optional) */
        .confetti {
            position: absolute;
            opacity: 0;
            pointer-events: none;
        }

        .confetti.active {
            opacity: 1;
        }
    </style>
</head>
<body>

    <div id="kanban-board" class="container mx-auto py-10">

        <!-- Columns -->
        <div class="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div data-testid="column-backlog" class="bg-white rounded shadow p-6 data-testid="column-backlog">
                <h2 class="text-2xl font-bold text-gray-800 mb-4">Backlog</h2>

                <!-- Add Card Button -->
                <button data-testid="add-card" class="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-md mt-4" onclick="addCard('Backlog')">Add Card</button>

                <!-- Dummy Cards (if no cards exist) -->
                <div id="dummy-backlog" class="cards">
                    <!-- Example dummy cards -->
                    <div class="card data-testid="card">
                        <h3 class="text-xl font-semibold">Task 1</h3>
